/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels
 * (email, SMS, webhook). Each user has one preferences record. If none exists,
 * defaults apply.
 *
 * Decision change (Session 9): The original model assumed email-only delivery.
 * With SMS support added in Session 8 and webhook already available, the model
 * now supports per-channel settings. Email defaults to enabled (backward
 * compatible); SMS defaults to disabled (requires explicit opt-in due to
 * regulatory/cost considerations); webhook defaults to disabled.
 */

import type { NotificationType } from './notification.js';

/**
 * How often batched email notifications are delivered.
 * - 'immediate': send as events occur
 * - 'daily': batch into a daily digest
 * - 'weekly': batch into a weekly digest
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Notification categories that a user can subscribe to or unsubscribe from.
 * Maps directly to NotificationType values.
 */
export type NotificationCategory = NotificationType;

/**
 * Base notification settings shared by all channels.
 * Each channel can be independently enabled/disabled and has its own
 * unsubscribed categories list.
 */
export interface ChannelNotificationSettings {
  enabled: boolean;
  unsubscribedCategories: NotificationCategory[];
}

/**
 * Email-specific notification settings.
 * Extends base settings with email-specific frequency control.
 */
export interface EmailNotificationSettings extends ChannelNotificationSettings {
  frequency: EmailFrequency;
}

/**
 * SMS-specific notification settings.
 * SMS defaults to disabled — requires explicit opt-in due to carrier costs
 * and regulatory compliance (TCPA, GDPR).
 */
export interface SmsNotificationSettings extends ChannelNotificationSettings {}

/**
 * Webhook-specific notification settings.
 * Webhook defaults to disabled — requires explicit configuration of an endpoint.
 */
export interface WebhookNotificationSettings extends ChannelNotificationSettings {}

/**
 * Full user notification preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailNotificationSettings;
  sms: SmsNotificationSettings;
  webhook: WebhookNotificationSettings;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences (userId required, rest has defaults).
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailNotificationSettings>;
  sms?: Partial<SmsNotificationSettings>;
  webhook?: Partial<WebhookNotificationSettings>;
}

/**
 * Input for updating existing preferences.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailNotificationSettings>;
  sms?: Partial<SmsNotificationSettings>;
  webhook?: Partial<WebhookNotificationSettings>;
}

/**
 * Default email notification settings applied when no preferences exist.
 * Email is enabled by default for backward compatibility.
 */
export const DEFAULT_EMAIL_SETTINGS: EmailNotificationSettings = {
  enabled: true,
  frequency: 'immediate',
  unsubscribedCategories: [],
};

/**
 * Default SMS notification settings.
 * Disabled by default — SMS requires explicit opt-in due to cost and
 * regulatory requirements (TCPA, GDPR consent for SMS).
 */
export const DEFAULT_SMS_SETTINGS: SmsNotificationSettings = {
  enabled: false,
  unsubscribedCategories: [],
};

/**
 * Default webhook notification settings.
 * Disabled by default — webhooks require explicit endpoint configuration.
 */
export const DEFAULT_WEBHOOK_SETTINGS: WebhookNotificationSettings = {
  enabled: false,
  unsubscribedCategories: [],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Handles serialization of per-channel notification settings to/from
 * flat database records.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationCategory, EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        unsubscribedCategories: JSON.parse(
          record['emailUnsubscribedCategories'] as string,
        ) as NotificationCategory[],
      },
      sms: {
        enabled: (record['smsEnabled'] as boolean | undefined) ?? false,
        unsubscribedCategories: record['smsUnsubscribedCategories']
          ? (JSON.parse(record['smsUnsubscribedCategories'] as string) as NotificationCategory[])
          : [],
      },
      webhook: {
        enabled: (record['webhookEnabled'] as boolean | undefined) ?? false,
        unsubscribedCategories: record['webhookUnsubscribedCategories']
          ? (JSON.parse(record['webhookUnsubscribedCategories'] as string) as NotificationCategory[])
          : [],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailUnsubscribedCategories: JSON.stringify(entity.email.unsubscribedCategories),
      smsEnabled: entity.sms.enabled,
      smsUnsubscribedCategories: JSON.stringify(entity.sms.unsubscribedCategories),
      webhookEnabled: entity.webhook.enabled,
      webhookUnsubscribedCategories: JSON.stringify(entity.webhook.unsubscribedCategories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for user notification preferences.
 *
 * Manages CRUD operations for user notification preferences and provides
 * a query interface used by NotificationService to check whether a
 * notification should be sent to a given user on a given channel.
 *
 * Supports per-channel preferences for email, SMS, and webhook.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 */

import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
  NotificationCategory,
} from '../models/user-preferences.js';
import {
  DEFAULT_EMAIL_SETTINGS,
  DEFAULT_SMS_SETTINGS,
  DEFAULT_WEBHOOK_SETTINGS,
} from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Create preferences for a user. Merges provided settings with defaults.
   * Throws if preferences already exist for the user.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    this.logger.info(`Creating preferences for user: ${input.userId}`);

    const existing = this.preferencesRepository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const now = new Date();
    const prefs: UserPreferences = {
      id: generateId(),
      userId: input.userId,
      email: {
        ...DEFAULT_EMAIL_SETTINGS,
        ...input.email,
      },
      sms: {
        ...DEFAULT_SMS_SETTINGS,
        ...input.sms,
      },
      webhook: {
        ...DEFAULT_WEBHOOK_SETTINGS,
        ...input.webhook,
      },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(prefs);
    return prefs;
  }

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, falling back to defaults if none exist.
   */
  getPreferencesOrDefaults(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    return {
      id: '',
      userId,
      email: { ...DEFAULT_EMAIL_SETTINGS },
      sms: { ...DEFAULT_SMS_SETTINGS },
      webhook: { ...DEFAULT_WEBHOOK_SETTINGS },
      createdAt: new Date(),
      updatedAt: new Date(),
    };
  }

  /**
   * Update a user's preferences. Only provided fields are changed.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    this.logger.info(`Updating preferences for user: ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      throw new Error(`Preferences not found for user: ${userId}`);
    }

    const updatedEmail = input.email
      ? { ...existing.email, ...input.email }
      : existing.email;

    const updatedSms = input.sms
      ? { ...existing.sms, ...input.sms }
      : existing.sms;

    const updatedWebhook = input.webhook
      ? { ...existing.webhook, ...input.webhook }
      : existing.webhook;

    const updated = this.preferencesRepository.update(existing.id, {
      email: updatedEmail,
      sms: updatedSms,
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });

    return updated;
  }

  /**
   * Delete a user's preferences (resets to defaults).
   */
  deletePreferences(userId: string): boolean {
    this.logger.info(`Deleting preferences for user: ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      return false;
    }

    return this.preferencesRepository.delete(existing.id);
  }

  /**
   * Check whether a specific email notification should be sent to a user.
   * Returns true if email is enabled and the category is not unsubscribed.
   *
   * @deprecated Use shouldSendNotification(userId, 'email', notificationType) instead.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSendNotification(userId, 'email', notificationType);
  }

  /**
   * Check whether a notification should be sent to a user on a given channel.
   * Returns true if the channel is enabled and the category is not unsubscribed.
   *
   * For channels without preference support (e.g. in_app), defaults to allowing
   * the notification.
   */
  shouldSendNotification(
    userId: string,
    channel: NotificationChannel,
    notificationType: NotificationType,
  ): boolean {
    const prefs = this.getPreferencesOrDefaults(userId);

    const channelSettings = this.getChannelSettings(prefs, channel);
    if (!channelSettings) {
      // No preference model for this channel — allow by default
      return true;
    }

    if (!channelSettings.enabled) {
      this.logger.debug(`${channel} disabled for user: ${userId}`);
      return false;
    }

    if (channelSettings.unsubscribedCategories.includes(notificationType as NotificationCategory)) {
      this.logger.debug(
        `User ${userId} unsubscribed from category ${notificationType} on ${channel}`,
      );
      return false;
    }

    return true;
  }

  /**
   * Get the channel-specific settings from a preferences record.
   * Returns undefined for channels that don't have preference support.
   */
  private getChannelSettings(
    prefs: UserPreferences,
    channel: NotificationChannel,
  ) {
    switch (channel) {
      case 'email':
        return prefs.email;
      case 'sms':
        return prefs.sms;
      case 'webhook':
        return prefs.webhook;
      default:
        return undefined;
    }
  }
}

